        /// <param name="bankid"></param>
        /// <param name="consentid"></param>
        /// <param name="answerConsentChallengeRequest"></param>
        /// <returns></returns>
        private void ValidateAnswerConsentChallenge(string bankid, string consentid, AnswerConsentChallengeRequest answerConsentChallengeRequest)
        {
            if (bankid == null)
                throw new ArgumentNullException(nameof(bankid));

            if (consentid == null)
                throw new ArgumentNullException(nameof(consentid));

            if (answerConsentChallengeRequest == null)
                throw new ArgumentNullException(nameof(answerConsentChallengeRequest));
        }

