        private void AfterAnswerConsentChallengeDefaultImplementation(IAnswerConsentChallengeApiResponse apiResponseLocalVar, string bankid, string consentid, AnswerConsentChallengeRequest answerConsentChallengeRequest)
        {
            bool suppressDefaultLog = false;
            AfterAnswerConsentChallenge(ref suppressDefaultLog, apiResponseLocalVar, bankid, consentid, answerConsentChallengeRequest);
            if (!suppressDefaultLog)
                Logger.LogInformation("{0,-9} | {1} | {2}", (apiResponseLocalVar.DownloadedAt - apiResponseLocalVar.RequestedAt).TotalSeconds, apiResponseLocalVar.StatusCode, apiResponseLocalVar.Path);
        }

