        private void OnErrorCreateTransactionRequestRefundDefaultImplementation(Exception exceptionLocalVar, string pathFormatLocalVar, string pathLocalVar, string bankid, string accountid, string viewid, string refund, CreateTransactionRequestRefundRequest createTransactionRequestRefundRequest)
        {
            bool suppressDefaultLogLocalVar = false;
            OnErrorCreateTransactionRequestRefund(ref suppressDefaultLogLocalVar, exceptionLocalVar, pathFormatLocalVar, pathLocalVar, bankid, accountid, viewid, refund, createTransactionRequestRefundRequest);
